简单的方式—使用 operator
格式:
返回类型 operator运算符(参数)&#123;    //do something    return 返回值;    //do something&#125;
举个栗子: 重载&quot;+&quot;计算时间
#include &lt;iostream&gt;using namespace std;struct Time&#123;	int minute, hour;&#125; x, y;Time operator+(Time a, Time b)&#123;	Time c;	c.minute = a.minute + b.minute;	c.hour = a.hour + b.hour;	while (c.minute &gt;= 60)	&#123;		c.hour += c.minute / 60;		c.minute %= 60;	&#125;	return c;&#125;int main()&#123;	cin &gt;&gt; x.hour &gt;&gt; x.minute;	cin &gt;&gt; y.hour &gt;&gt; y.minute;	Time z;	z = x + y;	cout &lt;&lt; z.hour &lt;&lt; &quot; &quot; &lt;&lt; z.minute;	return 0;&#125;

快速幂
int qp(int a, int b) &#123;          //quick_power	int ans = 1;	for (; b; b &gt;&gt;= 1) &#123;		if (b &amp; 1) ans = (long long)ans * a;		a = (long long)a * a;	&#125;	return ans;&#125;
矩阵乘法
设A为m×pm \times pm×p的矩阵，B为p×np \times np×n的矩阵，那么称m×nm \times nm×n的矩阵C为矩阵A与B的乘积，记作C=ABC = ABC=AB，其中矩阵C中的第iii行第jjj列元素可以表示为：
Ci,j=∑k=1pai,k×bj,kC_{i,j}=\sum\limits_{k=1}^p a_{i,k} \times b_{j,k}Ci,j​=k=1∑p​ai,k​×bj,k​
如下所示：
[abcdef]×[ghijkl]=[ag+ch+ei,aj+ck+elbg+dh+fi,bj+dk+fl]\begin{bmatrix}a&amp;b\\c&amp;d\\e&amp;f\end{bmatrix} \times \begin{bmatrix}g&amp;h&amp;i\\j&amp;k&amp;l\end{bmatrix} = \begin{bmatrix}ag+ch+ei,&amp;aj+ck+el\\bg+dh+fi,&amp;bj+dk+fl\end{bmatrix}
​ace​bdf​​×[gj​hk​il​]=[ag+ch+ei,bg+dh+fi,​aj+ck+elbj+dk+fl​]
代码
jz operator*(const jz&amp; x, const jz&amp; y)   //为了方便快速幂采用运算符重载&#123;    jz z;    z.n = x.n;    for (int = 1; i &lt;= z.n; ++i)        for (int j = 1; j &lt;= z.n; ++j)            z.e[i][j] = INF;    for (int k = 1; k &lt;= z.n; ++k)        for (int i = 1; i &lt;= z.n; ++i)            for (int j = 1; j &lt;= z.n; ++j)                    z.e[i][j] += x.e[i][k] + y.e[k][j];    return z;&#125;
所以，矩阵快速幂即为作若干次矩阵乘法，代码如下：
完整代码
#define N 1010struct jz          //矩阵&#123;    short n;    long long e[N][N];&#125; a;jz operator*(const jz&amp; x, const jz&amp; y)&#123;    short i, j, k;    jz z;    z.n = x.n;    for (i = 1; i &lt;= z.n; ++i)        for (j = 1; j &lt;= z.n; ++j)            z.e[i][j] = INF;    for (k = 1; k &lt;= z.n; ++k)        for (i = 1; i &lt;= z.n; ++i)            for (j = 1; j &lt;= z.n; ++j)                if (x.e[i][k] + y.e[k][j] &lt; z.e[i][j])                    z.e[i][j] = x.e[i][k] + y.e[k][j];    return z;&#125;jz qp(jz a, int b) &#123;          //quick_power	jz ans = 1;	for (; b; b &gt;&gt;= 1) &#123;		if (b &amp; 1) ans = (long long)ans * a;		a = (long long)a * a;	&#125;	return ans;&#125;
